import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists(): return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing: existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]: existing[ch][v] = html

PSALMS = {
"34": {
"1": "<p><strong>ʾăbārĕkâ ʾet-YHWH bĕkol-ʿēt tāmîd tĕhillātô bĕpî</strong> (<em>ʾăḇāreḵâ ʾeṯ-YHWH bĕḵol-ʿēṯ tāmîḏ tĕhillāṯô ḇĕp̄î</em>): 'I will bless the LORD at all times; his praise shall continually be in my mouth.' Psalm 34 is an acrostic poem (each verse beginning with successive Hebrew letters, ʾālep through tāw), attributed to David's feigning of madness before Achish king of Gath (1 Sam 21:10-15 — the superscription uses 'Abimelech,' possibly a dynastic title for Philistine kings). The cohortative ʾăbārĕkâ ('I will bless') opens with resolve: tāmîd ('continually, always') negates any temporal limitation on praise. The phrase tĕhillātô bĕpî, 'his praise in my mouth,' locates worship in the mouth — the organ of both speech and ingestion, connecting to the later 'taste and see' of v.8.</p>",
"2": "<p><strong>baYHWH tithallēl napšî</strong> (<em>ḇaYHWH tiṯhallēl napšî</em>): 'My soul makes its boast in the LORD.' The hitpael tiṯhallēl ('boasts, glories') from hālal is reflexive — the soul's self-glorying redirected toward YHWH. The Pauline principle of 1 Cor 1:31 ('let the one who boasts, boast in the Lord') draws on this Psalter tradition (cf. Jer 9:23-24). The phrase yišmĕʿû ʿănāwîm wĕyiśmāḥû, 'the humble will hear and be glad,' introduces the ʿănāwîm as those who listen to testimony of rescue and share vicariously in the joy — the community of the poor who live by hearing good news of others' deliverance.</p>",
"3": "<p><strong>gaddĕlû laYHWH ʾittî ûnĕrômĕmâ šĕmô yaḥdāw</strong> (<em>ḡaddĕlû laYHWH ʾittî ûnĕrômĕmâ šĕmô yaḥdāw</em>): 'Oh, magnify the LORD with me, and let us exalt his name together!' The plural imperatives gaddĕlû ('make great!') and nĕrômĕmâ ('let us exalt!') invite communal amplification of praise. The adverb yaḥdāw ('together') is covenantal — individual rescue becomes corporate celebration. The 'name' (šēm) that is exalted encompasses YHWH's revealed character: the rescue of David (background of the psalm) becomes a public declaration about who YHWH is.</p>",
"4": "<p><strong>dāraštî ʾet-YHWH wĕʿānānî ûmikkol-mĕgûrôtay hiṣṣîlānî</strong> (<em>ḏāraštî ʾeṯ-YHWH wĕʿānānî ûmikkol-mĕḡûrôṯay hiṣṣîlānî</em>): 'I sought the LORD, and he answered me and delivered me from all my fears.' The verb dāraš ('to seek, inquire after') is the psalmist's primary act — the seeking that initiated the entire encounter. The reciprocal wĕʿānānî ('and he answered me') shows that seeking activates divine response. The noun mĕgûrôt ('fears, terrors') from gûr ('to sojourn, dread') is unusual — it may connote the alien anxiety of someone in a foreign context (David among Philistines), making the historical backstory theologically loaded: fear of exile rescued by YHWH.</p>",
"5": "<p><strong>hibbîṭû ʾēlāyw wĕnāhārû ûpĕnêhem ʾal-yēḥpārû</strong> (<em>hibbîṭû ʾēlāyw wĕnāhārû ûp̄ĕnêhem ʾal-yēḥp̄ārû</em>): 'Those who looked to him were radiant, and their faces shall never be ashamed.' The plural hibbîṭû ('they looked') shifts from David's individual experience to the community's: looking toward YHWH has a visible effect — wĕnāhārû ('they were radiant'), from nāhar ('to shine, stream, be radiant'). The shamelessness of their faces — ûpĕnêhem ʾal-yēḥpārû — echoes the Psalter's consistent prayer (e.g., Ps 25:2-3) that those who trust YHWH will not be put to shame. The inversion: looking toward YHWH produces light; looking away produces shame.</p>",
"6": "<p><strong>zeh ʿānî qārāʾ wĕYHWH šāmaʿ ûmikkol-ṣārôtāyw hôšîʿô</strong> (<em>zeh ʿānî qārāʾ wĕYHWH šāmaʿ ûmikkol-ṣārôṯāyw hôšîʿô</em>): 'This poor man cried, and the LORD heard him and saved him out of all his troubles.' The demonstrative zeh ʿānî ('this poor man') is emphatic and personal — David identifies himself as the paradigmatic ʿānî ('afflicted/poor one'). The sequence qārāʾ → šāmaʿ → hôšîʿ ('cried → heard → saved') is the compressed rescue narrative of the entire Psalter. The psalm is not just testimony about YHWH's past action but a pattern: ʿānî + cry → YHWH hears → rescue. Peter applies this pattern to Jesus (1 Pet 5:7).</p>",
"7": "<p><strong>ḥōneh malʾak YHWH sābîb lîrēʾāyw wayyĕḥallĕṣēm</strong> (<em>ḥōneh malʾak YHWH sāḇîḇ lîrēʾāyw wayyĕḥallĕṣēm</em>): 'The angel of the LORD encamps around those who fear him and delivers them.' The participle ḥōneh ('encamps, sets up camp') from ḥānâ applies military encampment language to divine protection: the divine envoy establishes a perimeter. The malʾak YHWH ('messenger/angel of the LORD') in the OT is often indistinguishable from YHWH himself (Gen 16:7-13; 22:11-18; Exod 3:2-6) — an anticipation of the Second Person's mediatorial role. The scope: lîrēʾāyw ('for those who fear him') — the protective encampment is covenant-shaped, not universal. The hiphil wayyĕḥallĕṣēm ('and he delivers them') from ḥālaṣ ('to draw out') describes rescue as extraction from danger.</p>",
"8": "<p><strong>ṭaʿămû ûrĕʾû kî ṭôb YHWH</strong> (<em>ṭaʿămû ûrĕʾû kî ṭôḇ YHWH</em>): 'Oh, taste and see that the LORD is good.' The imperatives ṭaʿămû ('taste!') and rĕʾû ('see!') are synesthetic — taste and sight combined invite experiential rather than merely intellectual knowledge of divine goodness. The verb ṭāʿam ('to taste, perceive by eating') makes covenant knowledge bodily: one does not merely learn about YHWH's goodness but experiences it as real as food in the mouth. 1 Peter 2:3 cites this verse: 'if indeed you have tasted that the Lord is good' — applied to the community's experience of Christ. The following beatitude ʾašrê haggeber yeḥĕseh-bô, 'blessed is the man who takes refuge in him,' links tasting to ḥāsâ-trust.</p>",
"9": "<p><strong>yĕrĕʾû ʾet-YHWH qĕdōšāyw kî ʾên maḥsôr lîrēʾāyw</strong> (<em>yĕrĕʾû ʾeṯ-YHWH qĕḏôšāyw kî ʾên maḥsôr lîrēʾāyw</em>): 'Oh, fear the LORD, you his holy ones, for those who fear him have no lack!' The imperative yĕrĕʾû is directed at qĕdōšāyw ('his holy ones, his consecrated ones') — the covenant community already set apart for YHWH. Fear here (yārēʾ) is not terror but the reverence that orientates all of life toward YHWH. The promise: ʾên maḥsôr lîrēʾāyw, 'no lack to those who fear him' — the noun maḥsôr ('want, lack, deficiency') is negated absolutely. Those who fear YHWH have no permanent deficiency; the root of all their needs is met in him.</p>",
"10": "<p><strong>kĕpîrîm rāšû wĕrāʿēbû wĕdōrĕšê YHWH lōʾ-yaḥsĕrû kol-ṭôb</strong> (<em>kĕp̄îrîm rāšû wĕrāʿēḇû wĕḏōrĕšê YHWH lōʾ-yaḥsĕrû ḵol-ṭôḇ</em>): 'The young lions suffer want and hunger, but those who seek the LORD lack no good thing.' The contrast is between kĕpîrîm ('young lions' — the most powerful predators in their prime strength) and dōrĕšê YHWH ('those who seek the LORD'). Young lions — paragons of physical power and hunting ability — still experience rāšû ('become poor') and rāʿēbû ('hunger'). But the YHWH-seekers yaḥsĕrû... kol-ṭôb ('lack no good thing'). Power and provision are not correlated — seeking YHWH, not personal strength, is the ground of sufficiency.</p>",
"11": "<p><strong>lĕkû bānîm šimʿû-lî yirʾat YHWH ʾălammēdkem</strong> (<em>lĕḵû ḇānîm šimʿû-lî yirʾaṯ YHWH ʾălammēḏkem</em>): 'Come, O children, listen to me; I will teach you the fear of the LORD.' The shift to wisdom-address — lĕkû bānîm ('come, children') — transforms the psalm from personal testimony to pedagogical discourse: David's rescue becomes a teaching moment. The phrase yirʾat YHWH ʾălammēdkem, 'I will teach you the fear of the LORD,' identifies the fear of YHWH as teachable — a disposition cultivated by instruction and practice, not merely intuited. This verse inaugurates the sapiential center of the psalm (vv.11-14).</p>",
"12": "<p><strong>mî-hāʾîš heḥāpēṣ ḥayyîm ʾōhēb yāmîm lirʾôt ṭôb</strong> (<em>mî-hāʾîš heḥāpēṣ ḥayyîm ʾōhēb yāmîm lirʾôṯ ṭôḇ</em>): 'What man is there who desires life and loves many days, that he may see good?' The rhetorical question mî-hāʾîš ('what man?') creates a universally appealing hook: who does not desire life and good days? The two participles heḥāpēṣ ḥayyîm ('who desires life') and ʾōhēb yāmîm ('who loves days') are universal — the question's answer is everyone. The condition 'to see good' (lirʾôt ṭôb) picks up the 'see' of v.8's synesthetic invitation: seeing good is possible, and the means is covenant wisdom.</p>",
"13": "<p><strong>nĕṣōr lĕšônĕkā mērāʿ ûśĕpātêkā middabbēr mirmâ</strong> (<em>nĕṣōr lĕšôneḵā mērāʿ ûśĕp̄āṯeḵā middabbēr mirmâ</em>): 'Keep your tongue from evil and your lips from speaking deceit.' The verb nāṣar (qal imperative, 'guard, keep watch') — a military term — applied to the tongue describes speech as a territory to be defended. The contrast between ṭôb ('good') and rāʿ ('evil'), ʾĕmet ('truth') and mirmâ ('deceit'), frames the tongue as the battleground of covenantal integrity. Peter quotes vv.12-16 extensively in 1 Pet 3:10-12, applying the ethical instruction of this psalm to the Christian community's social witness — the passage from Psalter wisdom becomes apostolic exhortation.</p>",
"14": "<p><strong>sûr mērāʿ waʿăśēh-ṭôb baqqēš šālôm wĕrādĕpēhû</strong> (<em>sûr mērāʿ waʿăśēh-ṭôb baqqēš šālôm wĕrāḏĕp̄ēhû</em>): 'Turn away from evil and do good; seek peace and pursue it.' The four imperatives create a complete ethical program: sûr ('turn away') + waʿăśēh ('do') + baqqēš ('seek') + wĕrādĕpēhû ('pursue'). The verb rādap ('pursue') — normally of enemies chasing someone (cf. Ps 7:1) — is applied to šālôm ('peace'): peace must be actively chased, not passively hoped for. The movement from avoidance (sûr mērāʿ) to action (ʿăśēh ṭôb) to pursuit (rādap šālôm) describes the full range of ethical life, corresponding to the OT/NT summary of avoiding evil and doing good (Rom 12:9; 1 Pet 3:11).</p>",
"15": "<p><strong>ʿênê YHWH ʾel-ṣaddîqîm wĕʾoznāyw ʾel-šawʿātām</strong> (<em>ʿênê YHWH ʾel-ṣaddîqîm wĕʾoznāyw ʾel-šawʿāṯām</em>): 'The eyes of the LORD are toward the righteous and his ears toward their cry.' The double divine attention — ʿênê YHWH ('eyes of the LORD') and ʾoznāyw ('his ears') — ensures complete sensory coverage: YHWH both sees the righteous and hears their cry. Peter cites this verse in 1 Pet 3:12 as the theological ground for the ethical instruction of vv.13-14: righteous conduct is worth maintaining because YHWH is watching and listening. The noun šawʿâ ('cry for help') is the desperate outcry of those in extremity — the same type of cry that initiates rescue throughout the Psalter.</p>",
"16": "<p><strong>pĕnê YHWH bĕʿōśê rāʿ lĕhakrît mēʾereṣ zikrām</strong> (<em>p̄ĕnê YHWH bĕʿōśê rāʿ lĕhaḵrîṯ mēʾereṣ zikrām</em>): 'The face of the LORD is against those who do evil, to cut off the memory of them from the earth.' The contrast with v.15 is structurally intentional: YHWH's face (pānîm) is oriented toward the righteous beneficially (v.15) but toward evildoers destructively. The phrase lĕhakrît mēʾereṣ zikrām, 'to cut off their memory from the earth,' invokes the covenant curse of obliterated remembrance (cf. Ps 9:5; Deut 9:14). Memory-erasure is the final form of judgment: not just death but the annihilation of legacy. Peter also quotes this verse, bracketing the moral teaching with divine scrutiny from both sides.</p>",
"17": "<p><strong>ṣāʿăqû wĕYHWH šāmaʿ ûmikkol-ṣārôtām hiṣṣîlām</strong> (<em>ṣāʿăqû wĕYHWH šāmaʿ ûmikkol-ṣārôṯām hiṣṣîlām</em>): 'When the righteous cry for help, the LORD hears and delivers them out of all their troubles.' The sequence ṣāʿăqû → šāmaʿ → hiṣṣîlām ('cried → heard → delivered') repeats the pattern of v.6 with generalizing third-person plurals: what happened to David (v.6) is paradigmatic for all the righteous. The noun ṣārôt ('troubles, straits') encompasses every form of distress — and the promise applies to mikkol ('out of all'), without exception. The righteousness that attracts YHWH's hearing is the covenant loyalty described in vv.13-14, not moral perfection.</p>",
"18": "<p><strong>qārôb YHWH lĕnišbĕrê-lēb wĕʾet-dakkĕʾê rûaḥ yôšîaʿ</strong> (<em>qārôḇ YHWH lĕnišbĕrê-lēḇ wĕʾeṯ-daḵḵĕʾê rûaḥ yôšîaʿ</em>): 'The LORD is near to the brokenhearted and saves the crushed in spirit.' The two recipients — nišbĕrê-lēb ('broken of heart, shattered in heart') and dakkĕʾê rûaḥ ('crushed of spirit') — describe the person who has experienced catastrophic loss of inner resilience. The adjective dakkāʾ ('crushed, pulverized') from dakāʾ implies being ground down to powder — not merely injured but disintegrated. To such persons YHWH is qārôb ('near') — not distant and requiring approach but already proximate. Jesus's beatitude 'blessed are the poor in spirit' (Matt 5:3) and Isa 61:1's mission to 'bind up the brokenhearted' both draw on this verse's theology.</p>",
"19": "<p><strong>rabbôt rāʿôt ṣaddîq ûmikkullām yaṣṣîlennû YHWH</strong> (<em>rabbôṯ rāʿôṯ ṣaddîq ûmikkulām yaṣṣîlennû YHWH</em>): 'Many are the afflictions of the righteous, but the LORD delivers him out of them all.' The phrase rabbôt rāʿôt ṣaddîq ('many are the troubles of the righteous') is not a complaint but a description — righteous people do suffer, and much. The psalm refuses the false theology that righteousness guarantees comfort. But the counter: ûmikkullām yaṣṣîlennû YHWH ('from all of them the LORD delivers him') — the word kullām ('all of them') makes the rescue scope absolute. The righteous suffer much AND are delivered completely. Both are true; neither cancels the other (cf. 2 Cor 4:8-9; Acts 14:22).</p>",
"20": "<p><strong>šōmēr kol-ʿaṣmôtāyw ʾaḥat mēhēnnâ lōʾ nišbārâ</strong> (<em>šōmēr ḵol-ʿaṣmôṯāyw ʾaḥaṯ mēhēnnâ lōʾ nišbārâ</em>): 'He keeps all his bones; not one of them is broken.' The verb šāmar ('guard, keep') applied to ʿaṣmôt ('bones') in the context of v.19's 'many afflictions' — YHWH protects even the skeletal structure of the righteous through suffering. John 19:36 explicitly cites this verse as fulfilled at the crucifixion: the soldiers did not break Jesus's legs (as was customary to hasten death) because he was already dead — John sees in this the fulfillment of Ps 34:20 (and Exod 12:46, the Passover bone-protection). The most literal fulfillment of a Psalter verse in the NT passion narrative.</p>",
"21": "<p><strong>tĕmôtēt rāšāʿ rāʿâ wĕśōnĕʾê ṣaddîq yĕʾšāmû</strong> (<em>ṯĕmôṯēṯ rāšāʿ rāʿâ wĕśōnĕʾê ṣaddîq yĕʾšāmû</em>): 'Affliction will slay the wicked, and those who hate the righteous will be condemned.' The verb mātat (hiphil, 'to cause to die') applied to the rāʿâ ('evil') that kills the rāšāʿ ('wicked') is an ironic reversal: evil, which the wicked used against others, destroys them. The phrase śōnĕʾê ṣaddîq yĕʾšāmû, 'those who hate the righteous will be condemned/guilty,' uses the niphal ʾāšam ('to become guilty, bear guilt') — the haters of the righteous are found guilty before YHWH's court. The reversal of vv.19-20 continues: the righteous suffer but are preserved; the wicked triumph but are finally destroyed by their own evil.</p>",
"22": "<p><strong>pôdeh YHWH nepeš ʿăbādāyw wĕlōʾ yĕʾšĕmû kol-haḥōsîm bô</strong> (<em>p̄ôḏeh YHWH nepeš ʿăḇāḏāyw wĕlōʾ yĕʾšĕmû ḵol-haḥōsîm ḇô</em>): 'The LORD redeems the life of his servants; none of those who take refuge in him will be condemned.' The participle pôdeh ('redeems') from pādâ ('to ransom, redeem') in present tense indicates ongoing activity: YHWH continuously ransoms. The object nepeš ʿăbādāyw ('the life of his servants') encompasses the whole person. The final promise — lōʾ yĕʾšĕmû kol-haḥōsîm bô, 'none who take refuge in him will be condemned' — returns to the ḥāsâ root of v.8 and answers v.21's condemnation of the wicked: the condemned are those who hate the righteous; those who take refuge are never condemned. The acrostic closes with an absolute guarantee of non-condemnation for the covenant community (cf. Rom 8:1).</p>"
},
"35": {
"1": "<p><strong>rîbâ YHWH ʾet-yĕrîbay lĕḥam ʾet-lōḥāmāy</strong> (<em>rîḇâ YHWH ʾeṯ-yĕrîḇay lĕḥam ʾeṯ-lōḥāmāy</em>): 'Contend, O LORD, with those who contend with me; fight against those who fight against me.' Psalm 35 is an imprecatory lament: the psalmist asks YHWH to act as his legal advocate (rîb — 'to contend at law, plead a case') and military champion (lāḥam — 'to fight'). The verb rîb belongs to the legal sphere: a rîb is a formal dispute or lawsuit. The psalmist frames his enemies as parties in a lawsuit against him and asks YHWH to take up his side of the case. The parallel lōḥāmāy ('those who fight against me') adds the military dimension: the legal and military metaphors interweave throughout the psalm, as they do in divine warrior texts (Exod 15; Isa 49:25-26).</p>",
"2": "<p><strong>haḥăzēq māgēn wĕṣinnâ wĕqûmâ bĕʿezrātî</strong> (<em>haḥăzēq māgēn wĕṣinnâ wĕqûmâ bĕʿezrātî</em>): 'Take hold of shield and buckler and rise for my help!' The imperatives haḥăzēq ('take firm hold!') and qûmâ ('arise!') summon YHWH as divine warrior. The two shields — māgēn (small round shield) and ṣinnâ (large body-covering shield) — represent comprehensive military protection. The phrase qûmâ bĕʿezrātî, 'arise for my help,' uses qûmâ as the liturgical summons to divine action (cf. Pss 7:6; 9:19; 10:12; 27:3). The request is concrete: the warrior-God is to arm himself and stand between the psalmist and his attackers.</p>",
"3": "<p><strong>wĕhāreq ḥănît ûsgōr liqrāʾt rōdĕpāy</strong> (<em>wĕhāreq ḥănîṯ ûs̱gōr liqrāʾṯ rōḏĕp̄āy</em>): 'Draw out the spear and javelin against my pursuers.' The hiphil hāreq ('draw out, unsheath') applied to the ḥănît ('spear') continues the military arming of YHWH. The phrase ʾĕmōr lĕnapšî yĕšûʿātek ʾānî, 'say to my soul: I am your salvation' — the divine speech-act that transforms the inner person. The requested word is yĕšûʿātek ʾānî ('I am your salvation') — not merely 'I will save you' but an identity declaration: YHWH as the essence of salvation. The psalmist needs not just help but the assurance that his helper is salvation itself.</p>",
"4": "<p><strong>yēbōšû wĕyikklĕmû mĕbaqqĕšê napšî</strong> (<em>yēḇōšû wĕyikkālĕmû mĕḇaqqĕšê napšî</em>): 'Let them be put to shame and dishonored who seek my life!' The paired jussives — yēbōšû ('let them be ashamed') and yikklĕmû ('let them be dishonored/humiliated') — are imprecatory prayers for the reversal of the enemies' plot. The phrase mĕbaqqĕšê napšî ('those who seek my life') describes those seeking the napšî — the whole person, not merely physical life. The additional pair yissōgû ʾāḥôr wĕyēḥpĕrû ('let them be turned back and confounded') amplifies the desired reversal: the attackers become the routed.</p>",
"5": "<p><strong>yihyû kĕmōṣ lipnê-rûaḥ ûmalʾak YHWH dôḥeh</strong> (<em>yihyû kĕmōṣ lip̄nê-rûaḥ ûmalʾak YHWH dôḥeh</em>): 'Let them be like chaff before the wind, with the angel of the LORD driving them away.' The chaff simile (kĕmōṣ lipnê-rûaḥ) pictures weight-lessness before power: the enemy who seemed substantial is revealed as insubstantial before the divine wind. The agent of their dispersal is malʾak YHWH ('the angel/messenger of the LORD') — the divine warrior's emissary who acts as enforcer of YHWH's judgments. The verb dôḥeh (hiphil participle from dāḥâ, 'to push, drive away') describes relentless pressure.</p>",
"6": "<p><strong>yĕhî darkām ḥōšek waḥălaqlaqqôt ûmalʾak YHWH rōdĕpām</strong> (<em>yĕhî ḏarḵām ḥōšeḵ waḥălaqlaqqôṯ ûmalʾak YHWH rōḏĕp̄ām</em>): 'Let their way be dark and slippery, with the angel of the LORD pursuing them.' The pairing of ḥōšek ('darkness') and ḥălaqlaqqôt ('slippery places') creates hazardous terrain without visible footing: the pursued cannot see where they step and the ground cannot be gripped. The angel of the LORD who was 'driving' (v.5) is now rōdĕpām ('pursuing') — the same verb used of the enemies' pursuit of the psalmist. The hunter becomes the hunted; divine agency reverses the predator-prey relationship.</p>",
"7": "<p><strong>kî ḥinnām ṭāmĕnû-lî šaḥat rišetām ḥinnām ḥāpĕrû lĕnapšî</strong> (<em>kî ḥinnām ṭāmĕnû-lî šaḥaṯ rišetām ḥinnām ḥāp̄ĕrû lĕnapšî</em>): 'For without cause they hid their net for me; without cause they dug a pit for my life.' The word ḥinnām ('without cause, for nothing, gratuitously') appears twice — a double emphasis on the unprovoked nature of the persecution. The two traps — rešet ('net') and šaḥat ('pit') — represent different modes of ambush. John 15:25 cites the word ḥinnām from this psalm: 'they hated me without cause' (combining Ps 35:19 and 69:4), applying the unprovoked hatred of the psalmist's enemies to the world's hatred of Jesus — the paradigmatic innocent sufferer.</p>",
"8": "<p><strong>tĕbôʾêhû šôʾâ lōʾ-yēdaʿ wĕrišetô ʾăšer ṭāman tilkĕdô</strong> (<em>ṯĕḇôʾêhû šôʾâ lōʾ-yēdaʿ wĕrišetô ʾăšer ṭāman tilkĕḏô</em>): 'Let destruction come upon him when he does not know it; let the net that he hid ensnare him.' The noun šôʾâ ('sudden ruin, catastrophe') — used of the day of devastation (cf. Isa 10:3; Zeph 1:15) — describes the unexpectedness of the wicked's doom: tĕbôʾêhû ... lōʾ-yēdaʿ ('let it come upon him without his knowing'). The lex talionis principle activates: wĕrišetô ʾăšer ṭāman tilkĕdô, 'let the net he hid catch him' — his own trap becomes his own capture. The planned ambush of v.7 returns on the planner (cf. Pss 7:15; 9:15-16).</p>",
"9": "<p><strong>wĕnapšî tāgîl baYHWH tāśîś bîšûʿātô</strong> (<em>wĕnapšî ṯāḡîl ḇaYHWH ṯāśîś bîšûʿāṯô</em>): 'Then my soul will rejoice in the LORD, exulting in his salvation.' The waw-consecutive wĕnapšî ('and my soul') signals the consequence of answered prayer: utter joy. The verb gîl ('rejoice, be glad') describes the bodily expression of spiritual elation; śîś ('exult, delight') adds intensity. Both are baYHWH and bîšûʿātô — in YHWH himself and in his yešûʿâ ('salvation'). The joy is not in the rescue alone but in the Rescuer: the act reveals the character of the one who acts, and the soul rejoices in the person discovered.</p>",
"10": "<p><strong>kol-ʿaṣmōtay tōʾmarnâ YHWH mî kāmôkā</strong> (<em>ḵol-ʿaṣmōṯay ṯōʾmarnâ YHWH mî ḵāmôḵā</em>): 'All my bones shall say, 'O LORD, who is like you?'' The phrase kol-ʿaṣmōtay ('all my bones') makes the entire skeleton — the structural self — a speaking chorus. The doxological question mî kāmôkā ('who is like you?') is the incomparability formula used throughout the OT (Exod 15:11; Pss 71:19; 89:8; Mic 7:18). The following words specify YHWH's incomparability: maṣṣîl ʿānî mēḥāzāq mimmennû wĕʿānî wĕʾebyôn mĕgōzlô, 'delivering the poor from one too strong for him, the poor and needy from one who robs him.' YHWH is uniquely the advocate of the structurally weak against the structurally powerful.</p>",
"11": "<p><strong>yĕqûmûn ʿēdê ḥāmās ʾăšer lōʾ-yādaʿtî yišʾālûnî</strong> (<em>yĕqûmûn ʿēḏê ḥāmās ʾăšer lōʾ-yāḏaʿtî yišʾālûnî</em>): 'Malicious witnesses rise up; they ask me of things I do not know.' The noun ʿēdê ḥāmās ('witnesses of violence') are perjurers — their testimony is not merely false but violent, designed to destroy. The phrase ʾăšer lōʾ-yādaʿtî yišʾālûnî, 'they ask me about things I do not know,' describes entrapment: questions about deeds never done or knowledge never possessed. The situation connects to the false witnesses against Jesus (Matt 26:60-61) and to the broader persecution motif that runs from the individual psalmist through to the Servant of Isaiah 53.</p>",
"12": "<p><strong>yĕšallĕmûnî rāʿâ taḥat ṭôbâ šĕkôl lĕnapšî</strong> (<em>yĕšallĕmûnî rāʿâ taḥaṯ ṭôḇâ šĕḵôl lĕnapšî</em>): 'They repay me evil for good, bereaving my soul.' The inversion rāʿâ taḥat ṭôbâ ('evil in place of good') is a recognized form of injustice throughout the OT: the ultimate perversion of reciprocity (cf. Prov 17:13; Ps 109:5; Rom 12:17). The noun šĕkôl ('bereavement, loss of children') describes the bereft state of a parent who has lost children — the most profound grief — applied to the napšî ('soul'): the psalmist's inner self is bereaved by the ingratitude of those he helped.</p>",
"13": "<p><strong>waʾănî bĕḥolotām lĕbûšî śāq ʿinnêtî batsôm napšî</strong> (<em>waʾănî bĕḥolotām lĕḇûšî śāq ʿinnêṯî ḇaṣṣôm napšî</em>): 'But I, when they were sick — I wore sackcloth; I afflicted myself with fasting.' The waw-adversative waʾănî ('but I') contrasts the enemies' ingratitude (v.12) with the psalmist's prior loyalty. The verbs — lābōš śāq ('wore sackcloth') and ʿinnâ bĕṣôm ('afflicted with fasting') — are mourning rites performed not for himself but for them: he fasted and wept over their illness. The phrase ûtĕpillātî ʿal-ḥêqî tāšûb, 'and my prayer returned to my bosom,' is difficult: either the prayer returned unanswered (possibly), or the psalmist's compassion turned back on himself (i.e., even his intercession for them produced personal grief).</p>",
"14": "<p><strong>kĕrēaʿ kĕʾāḥ-lî hiṯhallāktî kĕʾabel-ʾēm qōdēr šāḥôtî</strong> (<em>kĕrēaʿ kĕʾāḥ-lî hiṯhallāḵtî kĕʾāḇel-ʾēm qōḏēr šāḥôtî</em>): 'I went about as though I grieved for my friend or my brother; I bowed down in mourning as one who laments his mother.' The similes escalate: kĕrēaʿ ('like a friend') → kĕʾāḥ-lî ('like my own brother') → kĕʾabel-ʾēm ('like one mourning a mother'). The mourning gestures — qōdēr ('darkened, clad in dark garments') and šāḥôtî ('I bowed down') — enact grief publicly. The intensity of the mourning for the enemies' illness makes the enemies' ingratitude (v.12) all the more offensive: David mourned them like family, and they repaid him with violence.</p>",
"15": "<p><strong>ûbĕṣalʿî śāmĕḥû wĕneʾespû</strong> (<em>ûḇĕṣalʿî śāmĕḥû wĕneʾespû</em>): 'But at my stumbling they rejoiced and gathered.' The noun ṣālaʿ ('limping, stumbling') describes a momentary weakness or defeat — the psalmist's vulnerability. The response: śāmĕḥû ('they rejoiced') and neʾespû ('they gathered') — the gathering of mockers at the scene of another's pain. The phrase nēkîm śĕmûqîm ... lōʾ yādaʿtî, 'smiters whom I did not know gathered against me,' introduces anonymous attackers: not just known enemies but strangers who join in the assault. The social dimension is communal shame: public mockery from an assembled crowd.</p>",
"16": "<p><strong>bĕḥanpê lāʿăgê māʿôg ḥāraq ʿālay šinnêhem</strong> (<em>bĕḥanp̄ê lāʿăḡê māʿôḡ ḥāraqqû ʿālay šinnêhem</em>): 'Like profane mockers at a feast, they gnash their teeth at me.' The phrase ḥanpê lāʿăgê māʿôg ('godless jesters/mockers at a cake-feast') pictures those who mock at banquets — the context of contemptuous entertainment. The verb ḥāraš šinnayim ('gnash teeth') is the physical expression of rage and contempt (cf. Pss 37:12; 112:10; Lam 2:16). The enemies' enjoyment of the psalmist's suffering is a feast: his pain is their entertainment. The verb māʿôg ('cake, flat cake') may refer specifically to revelers who mock over food — those whose full stomachs enable their cruelty.</p>",
"17": "<p><strong>ʾădōnāy kammâ tirʾeh hāšîbâ napšî miššōʾêhem</strong> (<em>ʾăḏōnāy kammâ tirʾeh hāšîḇâ napšî miššōʾêhem</em>): 'O Lord, how long will you look on? Rescue my soul from their destruction.' The address ʾădōnāy ('my Lord') combined with kammâ tirʾeh ('how long will you see/watch?') is the lament of divine inaction: YHWH witnesses the injustice but appears to tolerate it. The verb rāʾâ ('to see') in this context means watching without intervening — the most maddening form of non-response. The petition hāšîbâ napšî ('restore my life') from šûb ('to bring back') — as if the soul has been taken or driven away and needs restoration — and yĕḥîdātî mikkĕpîrîm, 'my precious one from the young lions,' uses the same yĕḥîdâ ('precious one') as Ps 22:20.</p>",
"18": "<p><strong>ʾôdĕkā bĕqāhāl rāb bĕʿam ʿāṣûm ʾăhallĕlekā</strong> (<em>ʾôḏĕḵā bĕqāhāl rāḇ bĕʿam ʿāṣûm ʾăhallĕleḵā</em>): 'I will thank you in the great assembly; in the mighty throng I will praise you.' The vow of public praise (bĕqāhāl rāb, 'in the great congregation') is the psalmist's counter-offering to the enemies' feast (v.16): if they feast on his misfortune, he will make YHWH's deliverance a public feast of praise. The phrase bĕʿam ʿāṣûm ('in a mighty/numerous people') emphasizes the size of the audience — the vindication will be as public as the shame was. The praise is the response that transforms private rescue into communal testimony (cf. Ps 22:25).</p>",
"19": "<p><strong>ʾal-yiśmĕḥû-lî ʾōyĕbay šeqer śōnĕʾay ḥinnām ʾal-yiqrĕṣû ʿāyin</strong> (<em>ʾal-yiśmĕḥû-lî ʾōyĕbay šeqer śōnĕʾay ḥinnām ʾal-yiqrĕṣû ʿāyin</em>): 'Let not those rejoice over me who are wrongfully my foes, nor let those wink the eye who hate me without cause.' The key phrase śōnĕʾay ḥinnām ('those who hate me without cause') parallels v.7's ḥinnām — the unprovoked nature of the hatred is repeated. John 15:25 cites this phrase: 'They hated me without a cause,' applying the psalmist's experience of arbitrary persecution to Jesus. The gesture yiqrĕṣû ʿāyin ('wink the eye') is the gesture of hidden malice — the concealed pleasure of seeing another suffer, expressed through a private eye-movement that signals to confederates while maintaining a public face.</p>",
"20": "<p><strong>kî lōʾ šālôm yĕdabbĕrû wĕʿal ragʿê-ʾereṣ diwrê mirmôt yaḥăšōbûn</strong> (<em>kî lōʾ šālôm yĕḏabbĕrû wĕʿal raḡʿê-ʾereṣ diḇrê mirmôṯ yaḥăšōḇûn</em>): 'For they do not speak peace, but against those who are quiet in the land they devise words of deceit.' The contrast is between šālôm ('peace' — the content of righteous speech) and diwrê mirmôt ('words of deceit'). The target rĕgê hāʾāreṣ ('the quiet ones of the land') are those who live peaceably, uninvolved in conflict — precisely those who should be unmolested. The enemies target the peaceful: their predation is not retaliatory but predatory.</p>",
"21": "<p><strong>wayyarḥîbû ʿālay pîhem ʾāmĕrû heʾāḥ heʾāḥ rāʾătâ ʿênênû</strong> (<em>wayyarḥîbû ʿālay pîhem ʾāmĕrû heʾāḥ heʾāḥ rāʾāṯâ ʿênênû</em>): 'They open wide their mouths against me; they say, 'Aha, aha! Our eyes have seen it!'' The verb rāḥab ('to be wide, broad') in the hiphil wayyarḥîbû ('they opened wide') applied to the mouth describes the maximum exposure of mockery — the gaping maw of contempt (cf. Ps 22:13). The exclamation heʾāḥ heʾāḥ ('aha! aha!') is the vocalization of satisfied malice — the sound of enemies witnessing what they desired. The claim rāʾătâ ʿênênû ('our eyes have seen') is triumphant: they have witnessed the psalmist's downfall and now claim confirmation of their judgment against him.</p>",
"22": "<p><strong>rāʾîtâ YHWH ʾal-teḥĕraš ʾădōnāy ʾal-tirḥaq mimmennî</strong> (<em>rāʾîṯā YHWH ʾal-teḥĕraš ʾăḏōnāy ʾal-tirḥaq mimmennî</em>): 'You have seen, O LORD; be not silent! O Lord, be not far from me!' The perfect rāʾîtâ ('you have seen') turns the enemies' boast (v.21, 'our eyes have seen') against itself: YHWH has also seen, and his seeing is the ground of hope. The negative imperatives ʾal-teḥĕraš ('do not be silent!') and ʾal-tirḥaq ('do not be far!') pray against two modes of divine abandonment: silence (non-speech) and distance (non-presence). The psalmist wants YHWH to convert his silent seeing into active speech and presence.</p>",
"23": "<p><strong>hāʿîrâ wĕhāqîṣâ lĕmišpāṭî ʾĕlōhay waʾdōnāy lĕrîbî</strong> (<em>hāʿîrâ wĕhāqîṣâ lĕmišpāṭî ʾĕlōhay waʾḏōnāy lĕrîḇî</em>): 'Awake and rouse yourself for my vindication, for my cause, my God and my Lord!' The imperatives hāʿîrâ ('awake!') and hāqîṣâ ('rouse yourself!') treat YHWH as sleeping — the bold anthropomorphism of Ps 44:23 ('awake! why are you sleeping, O Lord?'). The cause is lĕmišpāṭî lĕrîbî ('for my vindication, for my lawsuit') — legal categories. YHWH is summoned as judge (ʾĕlōhay, 'my God') and advocate (waʾdōnāy, 'my Lord') in a case where the enemies have brought false testimony (v.11).</p>",
"24": "<p><strong>šopĕṭēnî kĕṣidqĕkā YHWH ʾĕlōhāy wĕʾal-yiśmĕḥû-lî</strong> (<em>šop̄ĕṭēnî ḵĕṣiḏqĕḵā YHWH ʾĕlōhāy wĕʾal-yiśmĕḥû-lî</em>): 'Vindicate me, O LORD my God, according to your righteousness, and let them not rejoice over me!' The imperative šopĕṭēnî ('vindicate me, judge me') grounds the request in kĕṣidqĕkā ('according to your righteousness') — the psalmist appeals not to his own merit but to YHWH's covenant character. The prayer against rejoicing — wĕʾal-yiśmĕḥû-lî ('let them not rejoice over me') — returns to the opening petition (v.4: yiśmĕḥû ʿālay ʾōyĕbay). The framing concern is the enemy's gloating, which would be a public victory for wickedness over covenant righteousness.</p>",
"25": "<p><strong>ʾal-yōʾmĕrû bĕlibbām heʾāḥ napšēnû ʾal-yōʾmĕrû billa'ănûhû</strong> (<em>ʾal-yōʾmĕrû bĕlibbām heʾāḥ napšēnû ʾal-yōʾmĕrû billa'ănûhû</em>): 'Let them not say in their hearts, 'Aha, our soul's desire!' Let them not say, 'We have swallowed him up.'' The inner speech ʾal-yōʾmĕrû bĕlibbām ('let them not say in their hearts') returns to the enemies' self-talk. The exclamation heʾāḥ napšēnû ('aha, what our soul desired!') reveals the predatory appetite behind the attack: the psalmist's downfall is what the enemies' nepeš ('appetite, desire') wanted. The metaphor billa'ănûhû ('we have swallowed him up') pictures consumption — the psalmist as prey devoured whole.</p>",
"26": "<p><strong>yēbōšû wĕyikklĕmû yaḥdāw śĕmēḥê rāʿātî</strong> (<em>yēḇōšû wĕyikkālĕmû yaḥdāw śĕmēḥê rāʿāṯî</em>): 'Let them be put to shame and disappointed altogether who rejoice at my calamity.' The verb śāmaḥ ('rejoice') at rāʿātî ('my calamity') identifies the enemies by their pleasure in another's suffering — Schadenfreude as a theological category. The shame they sought to impose on the psalmist is redirected: yēbōšû ('let them be shamed') and yikklĕmû ('let them be disgraced'). The additional prayer yilbĕšû-bōšet ûkĕlimmâ hammitgaddĕlîm ʿālay, 'let those who magnify themselves against me be clothed with shame and dishonor' — clothing is a metaphor for complete encasement in identity: shame becomes their permanent garment.</p>",
"27": "<p><strong>yārōnnû wĕyiśmĕḥû ḥăpēṣê ṣidqî</strong> (<em>yārōnnû wĕyiśmĕḥû ḥăp̄ēṣê ṣiḏqî</em>): 'Let those who delight in my righteousness shout for joy and be glad.' Against the enemies who delight in calamity (v.26) stand those who delight in ṣidqî ('my righteousness/vindication'): the community that wants righteous outcomes for the righteous. The phrase wĕyōʾmĕrû tāmîd yigdal YHWH haḥāpēṣ šĕlôm ʿabdô, 'and let them say continually, 'Great is the LORD, who delights in the peace of his servant!'' — the desired outcome of rescue is communal praise. YHWH's delight in šālôm for his servant is the theological assertion that peace for the righteous is not incidental but purposeful divine will.</p>",
"28": "<p><strong>ûlĕšônî tehgeh ṣidqātĕkā kol-hayyôm tĕhillātekā</strong> (<em>ûlĕšônî ṯehgeh ṣiḏqāṯĕḵā ḵol-hayyôm tĕhillāṯeḵā</em>): 'Then my tongue shall tell of your righteousness and of your praise all the day long.' The concluding vow ûlĕšônî tehgeh ('and my tongue shall murmur/declare') from hāgâ ('to mutter, meditate, declare') — the word used in Ps 1:2 for meditating on Torah — closes the imprecatory psalm with praise. The objects ṣidqātĕkā ('your righteousness') and tĕhillātekā ('your praise') are the content of the ongoing declaration: YHWH's righteous vindication of the innocent becomes the substance of a lifetime of worship. The imprecatory prayer resolves not in violence but in testimony.</p>"
},
"36": {
"1": "<p><strong>nĕʾum-peša lārāšāʿ bĕqereb libbî</strong> (<em>nĕʾum-p̄ešaʿ lārāšāʿ bĕqereb libbî</em>): 'Transgression speaks to the wicked deep in his heart.' The noun nĕʾum ('oracle, utterance') — normally reserved for prophetic speech (nĕʾum YHWH, 'oracle of the LORD') — is here attributed to peša ('transgression'): sin functions as a false prophet within the wicked person, uttering its own counterfeit oracle. The phrase bĕqereb libbî ('within my heart') is textually difficult — some read libbô ('his heart'): the oracle of transgression lodges in the wicked man's inner life. The result: ʾên paḥad ʾĕlōhîm lĕneged ʿênāyw, 'there is no fear of God before his eyes' (Paul quotes this in Rom 3:18, completing his OT catena of universal sinfulness).</p>",
"2": "<p><strong>kî-heḥĕlîq ʾēlāyw bĕʿênāyw limetsor ʾawōnô lišnōʾ</strong> (<em>kî-heḥĕlîq ʾēlāyw bĕʿênāyw limetsor ʾawōnô lišnōʾ</em>): 'For he flatters himself in his own eyes that his iniquity cannot be found out and hated.' The hiphil heḥĕlîq ('to make smooth, flatter') applied reflexively — heḥĕlîq ʾēlāyw ('he flatters himself') — describes the self-deceptive sycophancy of the sinner's internal voice: the false oracle of v.1 tells him he is fine. The phrase limetsor ʾawōnô lišnōʾ, 'to find out his iniquity and hate it,' describes the moral investigation that would expose him — but self-flattery prevents this self-knowledge. The wicked man's sin is invisible to himself; the blindness is the sin's deepest effect.</p>",
"3": "<p><strong>dibrê pîw ʾāwen ûmirmâ ḥādal lĕhaśkîl lĕhêṭîb</strong> (<em>diḇrê p̄îw ʾāwen ûmirmâ ḥāḏal lĕhaśkîl lĕhêṭîḇ</em>): 'The words of his mouth are trouble and deceit; he has ceased to act wisely and do good.' The mouth (peh) is again the diagnostic organ: dibrê ʾāwen ûmirmâ ('words of wickedness and deceit') reveal the heart's corruption (cf. Matt 12:34). The phrase ḥādal lĕhaśkîl lĕhêṭîb, 'he has ceased to act wisely and do good,' uses the perfect ḥādal ('to cease, stop') — the cessation of wisdom and goodness is not a gradual decline but an accomplished break. The wicked man has definitively stopped the two activities that define the righteous: śākal (act wisely) and hêṭîb (do good/act beneficially).</p>",
"4": "<p><strong>ʾāwen yĕḥaššōb ʿal-miškābô yityaṣṣēb ʿal-derek lōʾ-ṭôb rāʿ lōʾ yimʾās</strong> (<em>ʾāwen yĕḥaššōḇ ʿal-mišḵāḇô yiṯyaṣṣēḇ ʿal-ḏereḵ lōʾ-ṭôḇ rāʿ lōʾ yimʾās</em>): 'He plots trouble on his bed; he sets himself in a way that is not good; he does not reject evil.' The bedroom (miškāb) is where unguarded thought happens — and the wicked man's nocturnal activity is planning ʾāwen ('iniquity, wickedness'). The hitpael yityaṣṣēb ('he stations himself, sets himself') describes deliberate positioning on derek lōʾ-ṭôb ('a way that is not good') — understated irony: it is not merely 'not good' but actively evil. The conclusion rāʿ lōʾ yimʾās, 'evil he does not reject,' completes the portrait: night-scheming, deliberate path-taking, and the refusal to refuse evil. This is the full portrait of the hardened wicked, in contrast to the entering worshippers of Ps 24.</p>",
"5": "<p><strong>YHWH baššāmayim ḥasdekā ʾĕmûnātĕkā ʿad-šĕḥāqîm</strong> (<em>YHWH baššāmayim ḥasdĕḵā ʾĕmûnāṯĕḵā ʿaḏ-šĕḥāqîm</em>): 'Your steadfast love, O LORD, extends to the heavens; your faithfulness to the clouds.' After the portrait of the wicked (vv.1-4), the psalm pivots sharply to the fullness of divine character. The spatial imagery — baššāmayim ('to the heavens') and ʿad-šĕḥāqîm ('to the clouds') — uses the vertical dimension to express limitlessness: ḥesed ('steadfast love') and ʾĕmûnâ ('faithfulness, reliability') are not bounded attributes but reach upward without ceiling. The contrast is complete: the wicked's reach is to his bed and to wickedness; YHWH's reach is to the sky.</p>",
"6": "<p><strong>ṣidqātĕkā kĕhārê ʾēl mišpāṭêkā tĕhôm rabbâ</strong> (<em>ṣiḏqāṯĕḵā kĕhārê ʾēl mišpāṭêkā ṯĕhôm rabbâ</em>): 'Your righteousness is like the mountains of God; your judgments are like the great deep.' The two similes create a vertical pair: ṣĕdāqâ ('righteousness') compared to hārê ʾēl ('mountains of God,' i.e., mighty/towering mountains) — high and immovable. mišpāṭîm ('judgments') compared to tĕhôm rabbâ ('the great deep') — the primordial abyss whose depth is unfathomable. Both are inaccessible to full human comprehension but utterly reliable: the righteousness and judgment of YHWH are as real and as beyond human measure as the mountains and the ocean depths. Paul's doxology in Rom 11:33 echoes this: 'how unsearchable are his judgments!'</p>",
"7": "<p><strong>mah-yāqār ḥasdĕkā ʾĕlōhîm ûbĕnê ʾādām bĕṣēl kĕnāpêkā yeḥĕsāyûn</strong> (<em>mah-yāqār ḥasdĕḵā ʾĕlōhîm ûḇĕnê ʾāḏām bĕṣēl kĕnāp̄êḵā yeḥĕsāyûn</em>): 'How precious is your steadfast love, O God! The children of man take refuge in the shadow of your wings.' The exclamatory mah-yāqār ('how precious!') from yāqar ('to be precious, costly') applies economic language of extreme value to ḥesed. The image of refuge bĕṣēl kĕnāpêkā ('in the shadow of your wings') — the shadow being cool, protective, and intimate — draws on the mother-bird sheltering her young (Deut 32:11; Ps 17:8; 57:1; Matt 23:37). The phrase ûbĕnê ʾādām ('the children of man') universalizes the refuge: it is available to all humanity, not only to Israel, which is the psalm's implicit mission theology.</p>",
"8": "<p><strong>yirwĕyûn middešen bêtekā wĕnaḥal ʿădānêkā tašqēm</strong> (<em>yirwĕyûn middešen bêṯeḵā wĕnaḥal ʿăḏānêḵā ṯašqēm</em>): 'They feast on the abundance of your house, and you give them drink from the river of your delights.' The verb rāwâ ('to be saturated, drink one's fill') combined with middešen bêtekā ('from the richness/fat of your house') describes the sanctuary meal — the ḥesed of YHWH materialized as rich food. The phrase naḥal ʿădānêkā ('the river of your delights') uses the noun ʿeden — a word connected to 'Eden' (Gen 2:8) and meaning 'luxury, delight.' The river of YHWH's delights is the antithesis of the desert and the image of eschatological abundance (cf. Rev 22:1-2, 'the river of the water of life').</p>",
"9": "<p><strong>kî ʿimmĕkā mĕqôr ḥayyîm bĕʾôrkā nirʾeh-ʾôr</strong> (<em>kî ʿimmĕḵā mĕqôr ḥayyîm bĕʾôrĕḵā nirʾeh-ʾôr</em>): 'For with you is the fountain of life; in your light do we see light.' The phrase mĕqôr ḥayyîm ('fountain of life') identifies YHWH as the source of all vitality — life does not merely come from YHWH but is located ʿimmĕkā ('with you'). The chiastic bĕʾôrkā nirʾeh-ʾôr ('in your light we see light') is among the most theologically dense phrases in the OT: the light by which we perceive anything is itself derived from divine light. John's prologue echoes this: 'In him was life, and the life was the light of men' (John 1:4). The fountain and the light image together describe YHWH as the ground of both existence (life) and intelligibility (light).</p>",
"10": "<p><strong>mĕšōk ḥasdĕkā lĕyōdĕʿêkā wĕṣidqātĕkā lĕyišrê-lēb</strong> (<em>mĕšōk ḥasdĕḵā lĕyôḏĕʿêḵā wĕṣiḏqāṯĕḵā lĕyišrê-lēḇ</em>): 'Continue your steadfast love to those who know you, and your righteousness to the upright of heart!' The imperative mĕšōk ('draw out, prolong') from māšak ('to draw, extend') — as in drawing a line — applied to ḥesed asks for its continuation: not a new gift but the extension of an established pattern. The recipients lĕyōdĕʿêkā ('those who know you') and lĕyišrê-lēb ('the upright of heart') define the covenant community by knowledge and integrity — both qualities opposite to the wicked of vv.1-4.</p>",
"11": "<p><strong>ʾal-tĕbôʾēnî regel gaʾăwâ wĕyad-rĕšāʿîm ʾal-tĕnidēnî</strong> (<em>ʾal-ṯĕḇôʾēnî regel gaʾăwâ wĕyaḏ-rĕšāʿîm ʾal-ṯĕniḏēnî</em>): 'Let not the foot of arrogance come upon me, nor the hand of the wicked drive me away.' The spatial language of the wicked — regel gaʾăwâ ('the foot of pride/arrogance') and yad rĕšāʿîm ('the hand of the wicked') — frames the threat as a territorial incursion: arrogance presses down with its foot, wickedness reaches with its hand to displace. The noun gaʾăwâ ('pride') is the sin that fuels the wicked of vv.1-4: the oracle of transgression (v.1) produces the prideful self-flattery (v.2) that enables all subsequent wrongdoing.</p>",
"12": "<p><strong>šām nāplû pōʿălê ʾāwen dĕḥû wĕlōʾ-yākĕlû qûm</strong> (<em>šām nāplû p̄ōʿălê ʾāwen dĕḥû wĕlōʾ-yāḵĕlû qûm</em>): 'There the evildoers lie fallen; they are thrust down, unable to rise.' The deictic šām ('there!') points to a specific location of judgment — perhaps the place where the wicked fell in past divine action, serving as a sign. The verbs nāplû ('they have fallen'), dĕḥû ('they were thrust down'), and lōʾ-yāḵĕlû qûm ('they are unable to rise') describe the finality of the wicked's collapse: the fall is complete, the fall is passive (thrust down, not merely stumbled), and there is no recovery. Against the living waters of v.9 and the refuge under divine wings of v.7, the wicked have chosen the darkness of their bed-plotting (v.4) — and this is its end. The psalm closes with the scene of the wicked prostrate and immobile, the mirror-image of the righteous 'satisfied with your fat' (v.8).</p>"
}
}

def main():
    existing = load_comm('mkt-original', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-original', 'psalms', existing)
    total = sum(len(v) for v in PSALMS.values())
    print(f'Psalms 34-36 mkt-original written — {total} verses.')

if __name__ == '__main__': main()
